/**
 * MessageList - Chat Message List Component with Virtual Scrolling
 * Features:
 * - Virtual scrolling for performance (react-window)
 * - Auto-scroll to bottom with smart scroll detection
 * - Search functionality with result highlighting
 * - Search result navigation (next/previous)
 * - Empty state with welcome message
 */

import { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { List } from 'react-window';
import { MessageItem } from '../MessageItem/MessageItem';
import type { Message } from '../../../types/chat';
import styles from './MessageList.module.css';

interface MessageListProps {
  messages: Message[];
  currentStreamingMessage: Message | null;
  showThinking: boolean;
  onToggleMessageCollapse: (id: string) => void;
  onToggleThinkingCollapse: (id: string) => void;
  onDeleteMessage?: (id: string) => void;
  onRegenerateMessage?: (id: string) => void;
}

interface SearchState {
  query: string;
  results: SearchResult[];
  currentIndex: number;
}

interface SearchResult {
  messageId: string;
  startIndex: number;
  endIndex: number;
}

// Message row renderer for react-window
interface MessageRowProps {
  index: number;
  style: React.CSSProperties;
  data: {
    messages: Message[];
    showThinking: boolean;
    onToggleMessageCollapse: (id: string) => void;
    onToggleThinkingCollapse: (id: string) => void;
    onDeleteMessage?: (id: string) => void;
    onRegenerateMessage?: (id: string) => void;
    highlightedMessageId: string | null;
  };
}

const MessageRow = ({ index, style, data }: MessageRowProps) => {
  const { messages, showThinking, onToggleMessageCollapse, onToggleThinkingCollapse, onDeleteMessage, onRegenerateMessage, highlightedMessageId } = data;
  const message = messages[index];

  if (!message) return null;

  return (
    <div 
      style={{
        ...style,
        paddingBottom: '8px',
      }}
      className={highlightedMessageId === message.id ? styles.highlighted : ''}
    >
      <MessageItem
        message={message}
        showThinking={showThinking}
        onToggleCollapse={() => onToggleMessageCollapse(message.id)}
        onToggleThinking={() => onToggleThinkingCollapse(message.id)}
        onDelete={onDeleteMessage ? () => onDeleteMessage(message.id) : undefined}
        onRegenerate={onRegenerateMessage && message.role === 'assistant' ? () => onRegenerateMessage(message.id) : undefined}
      />
    </div>
  );
};

export function MessageList({
  messages,
  currentStreamingMessage,
  showThinking,
  onToggleMessageCollapse,
  onToggleThinkingCollapse,
  onDeleteMessage,
  onRegenerateMessage,
}: MessageListProps) {
  const listRef = useRef<List>(null);
  const outerRef = useRef<HTMLDivElement>(null);
  const shouldScrollRef = useRef(true);
  const [search, setSearch] = useState<SearchState>({
    query: '',
    results: [],
    currentIndex: -1,
  });
  const [listHeight, setListHeight] = useState(600);

  const allMessages = useMemo(() => {
    return currentStreamingMessage ? [...messages, currentStreamingMessage] : messages;
  }, [messages, currentStreamingMessage]);

  // Calculate list height based on container
  useEffect(() => {
    const updateHeight = () => {
      if (outerRef.current?.parentElement) {
        const containerHeight = outerRef.current.parentElement.clientHeight;
        const searchHeight = search.query ? 50 : 0;
        setListHeight(containerHeight - searchHeight);
      }
    };

    updateHeight();
    window.addEventListener('resize', updateHeight);
    return () => window.removeEventListener('resize', updateHeight);
  }, [search.query]);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    if (shouldScrollRef.current && listRef.current) {
      listRef.current.scrollToItem(allMessages.length - 1, 'end');
    }
  }, [allMessages.length]);

  // Handle scroll - detect if user manually scrolled up
  const handleScroll = useCallback(({ scrollOffset, scrollDirection }: { scrollOffset: number; scrollDirection: 'forward' | 'backward' }) => {
    if (outerRef.current && scrollDirection === 'backward') {
      shouldScrollRef.current = false;
    }
  }, []);

  // Search functionality
  const performSearch = useCallback((query: string) => {
    if (!query.trim()) {
      setSearch({ query: '', results: [], currentIndex: -1 });
      return;
    }

    const results: SearchResult[] = [];
    const lowerQuery = query.toLowerCase();

    allMessages.forEach((message) => {
      const textContent = message.content
        .filter((c) => c.type === 'text')
        .map((c) => c.text || '')
        .join(' ');

      const lowerText = textContent.toLowerCase();
      let index = 0;

      while ((index = lowerText.indexOf(lowerQuery, index)) !== -1) {
        results.push({
          messageId: message.id,
          startIndex: index,
          endIndex: index + query.length,
        });
        index += 1;
      }
    });

    setSearch({
      query,
      results,
      currentIndex: results.length > 0 ? 0 : -1,
    });
  }, [allMessages]);

  // Navigate to next search result
  const nextResult = useCallback(() => {
    if (search.results.length === 0) return;

    const newIndex = (search.currentIndex + 1) % search.results.length;
    setSearch((prev) => ({ ...prev, currentIndex: newIndex }));

    // Scroll to the message
    const messageIndex = allMessages.findIndex(
      m => m.id === search.results[newIndex].messageId
    );
    if (messageIndex >= 0 && listRef.current) {
      listRef.current.scrollToItem(messageIndex, 'center');
    }
  }, [search, allMessages]);

  // Navigate to previous search result
  const prevResult = useCallback(() => {
    if (search.results.length === 0) return;

    const newIndex = search.currentIndex <= 0 ? search.results.length - 1 : search.currentIndex - 1;
    setSearch((prev) => ({ ...prev, currentIndex: newIndex }));

    // Scroll to the message
    const messageIndex = allMessages.findIndex(
      m => m.id === search.results[newIndex].messageId
    );
    if (messageIndex >= 0 && listRef.current) {
      listRef.current.scrollToItem(messageIndex, 'center');
    }
  }, [search, allMessages]);

  // Clear search
  const clearSearch = useCallback(() => {
    setSearch({ query: '', results: [], currentIndex: -1 });
    shouldScrollRef.current = true;
  }, []);

  // Handle keyboard shortcuts for search navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!search.query) return;

      if (e.key === 'Enter' && e.shiftKey) {
        e.preventDefault();
        prevResult();
      } else if (e.key === 'Enter' && !e.shiftKey && search.results.length > 0) {
        if ((e.target as HTMLElement)?.classList?.contains(styles.searchInput)) {
          e.preventDefault();
          nextResult();
        }
      } else if (e.key === 'Escape') {
        clearSearch();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [search, nextResult, prevResult, clearSearch]);

  // Get highlighted message ID for current search result
  const highlightedMessageId = useMemo(() => {
    if (search.currentIndex >= 0 && search.results[search.currentIndex]) {
      return search.results[search.currentIndex].messageId;
    }
    return null;
  }, [search]);

  // Item data for react-window
  const itemData = useMemo(() => ({
    messages: allMessages,
    showThinking,
    onToggleMessageCollapse,
    onToggleThinkingCollapse,
    onDeleteMessage,
    onRegenerateMessage,
    highlightedMessageId,
  }), [allMessages, showThinking, onToggleMessageCollapse, onToggleThinkingCollapse, onDeleteMessage, onRegenerateMessage, highlightedMessageId]);

  if (allMessages.length === 0) {
    return (
      <div className={styles.empty}>
        <WelcomeMessage />
      </div>
    );
  }

  return (
    <div className={styles.container}>
      {/* Search Bar */}
      <div className={styles.searchBar}>
        <div className={styles.searchInputWrapper}>
          <SearchIcon />
          <input
            type="text"
            className={styles.searchInput}
            placeholder="Search messages..."
            value={search.query}
            onChange={(e) => performSearch(e.target.value)}
          />
          {search.query && (
            <button className={styles.clearBtn} onClick={clearSearch}>
              <CloseIcon />
            </button>
          )}
        </div>

        {search.results.length > 0 && (
          <div className={styles.searchNav}>
            <span className={styles.searchCount}>
              {search.currentIndex + 1} / {search.results.length}
            </span>
            <button className={styles.navBtn} onClick={prevResult} title="Previous (Shift+Enter)">
              <ChevronUpIcon />
            </button>
            <button className={styles.navBtn} onClick={nextResult} title="Next (Enter)">
              <ChevronDownIcon />
            </button>
          </div>
        )}
      </div>

      {/* Virtual Message List */}
      <div ref={outerRef} className={styles.listContainer}>
        <List
          ref={listRef}
          height={listHeight}
          itemCount={allMessages.length}
          itemSize={120} // Base height, MessageItem should adjust
          itemData={itemData}
          onScroll={handleScroll}
          className={styles.list}
        >
          {MessageRow}
        </List>
      </div>

      {/* Scroll to bottom button */}
      {!shouldScrollRef.current && (
        <button
          className={styles.scrollToBottom}
          onClick={() => {
            if (listRef.current) {
              listRef.current.scrollToItem(allMessages.length - 1, 'end');
              shouldScrollRef.current = true;
            }
          }}
          title="Scroll to bottom"
        >
          <ChevronDownIcon />
        </button>
      )}
    </div>
  );
}

function WelcomeMessage() {
  return (
    <div className={styles.welcome}>
      <div className={styles.logo}>π</div>
      <h1>Welcome to Pi Gateway</h1>
      <p>
        Your AI coding assistant. Start a conversation by typing a message below.
      </p>
      <div className={styles.tips}>
        <div className={styles.tip}>
          <TipIcon />
          <span>Use <kbd>Ctrl+Enter</kbd> to send</span>
        </div>
        <div className={styles.tip}>
          <TipIcon />
          <span>Type <code>/</code> for slash commands</span>
        </div>
        <div className={styles.tip}>
          <TipIcon />
          <span>Start with <code>!</code> for bash commands</span>
        </div>
        <div className={styles.tip}>
          <TipIcon />
          <span>Use <kbd>Ctrl+F</kbd> to search messages</span>
        </div>
      </div>
    </div>
  );
}

// ============================================================================
// Icons
// ============================================================================

function TipIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2}>
      <circle cx="12" cy="12" r="10" />
      <line x1="12" y1="16" x2="12" y2="12" />
      <line x1="12" y1="8" x2="12.01" y2="8" />
    </svg>
  );
}

function SearchIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2}>
      <circle cx="11" cy="11" r="8" />
      <line x1="21" y1="21" x2="16.65" y2="16.65" />
    </svg>
  );
}

function CloseIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2}>
      <line x1="18" y1="6" x2="6" y2="18" />
      <line x1="6" y1="6" x2="18" y2="18" />
    </svg>
  );
}

function ChevronUpIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2}>
      <polyline points="18 15 12 9 6 15" />
    </svg>
  );
}

function ChevronDownIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2}>
      <polyline points="6 9 12 15 18 9" />
    </svg>
  );
}

