}

// Message row renderer for react-window v2
const MessageRow = ({
  index,
  style,
  rowProps,
}: {
  index: number;
  style: React.CSSProperties;
  rowProps: RowProps;
}) => {
  const {
    messages,
    showThinking,
    onToggleMessageCollapse,
    onToggleThinkingCollapse,
    onDeleteMessage,
    onRegenerateMessage,
    highlightedMessageId,
  } = rowProps;
  const message = messages[index];

  if (!message) return null;

  return (
    <div
      style={{
        ...style,
        paddingBottom: '8px',
      }}
      className={highlightedMessageId === message.id ? styles.highlighted : ''}
    >
      <MessageItem
        message={message}
        showThinking={showThinking}
        onToggleCollapse={() => onToggleMessageCollapse(message.id)}
        onToggleThinking={() => onToggleThinkingCollapse(message.id)}
        onDelete={
          onDeleteMessage ? () => onDeleteMessage(message.id) : undefined
        }
        onRegenerate={
          onRegenerateMessage && message.role === 'assistant'
            ? () => onRegenerateMessage(message.id)
            : undefined
