};

export function MessageList({
  messages,
  currentStreamingMessage,
  showThinking,
  onToggleMessageCollapse,
  onToggleThinkingCollapse,
  onDeleteMessage,
  onRegenerateMessage,
}: MessageListProps) {
  const listRef = useListRef();
  const outerRef = useRef<HTMLDivElement>(null);
  const shouldScrollRef = useRef(true);
  const [search, setSearch] = useState<SearchState>({
    query: '',
    results: [],
    currentIndex: -1,
  });
  const [listHeight, setListHeight] = useState(600);

  const allMessages = useMemo(() => {
    return currentStreamingMessage
      ? [...messages, currentStreamingMessage]
      : messages;
  }, [messages, currentStreamingMessage]);

  // Calculate list height based on container
  useEffect(() => {
    const updateHeight = () => {
      if (outerRef.current?.parentElement) {
        const containerHeight = outerRef.current.parentElement.clientHeight;
        const searchHeight = search.query ? 50 : 0;
        setListHeight(containerHeight - searchHeight);
      }
    };

    updateHeight();
    window.addEventListener('resize', updateHeight);
    return () => window.removeEventListener('resize', updateHeight);
  }, [search.query]);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    if (shouldScrollRef.current && listRef.current) {
      listRef.current.scrollToRow({
        index: allMessages.length - 1,
        align: 'end',
      });
    }
  }, [allMessages.length, listRef]);

  // Search functionality
  const performSearch = useCallback(
    (query: string) => {
      if (!query.trim()) {
        setSearch({ query: '', results: [], currentIndex: -1 });
        return;
      }

      const results: SearchResult[] = [];
      const lowerQuery = query.toLowerCase();

      allMessages.forEach((message) => {
        const textContent = message.content
          .filter((c) => c.type === 'text')
          .map((c) => c.text || '')
          .join(' ');

        const lowerText = textContent.toLowerCase();
        let index = 0;

        while ((index = lowerText.indexOf(lowerQuery, index)) !== -1) {
          results.push({
            messageId: message.id,
            startIndex: index,
            endIndex: index + query.length,
          });
          index += 1;
        }
      });

      setSearch({
        query,
        results,
        currentIndex: results.length > 0 ? 0 : -1,
      });
    },
    [allMessages]
  );

  // Navigate to next search result
  const nextResult = useCallback(() => {
    if (search.results.length === 0) return;

    const newIndex = (search.currentIndex + 1) % search.results.length;
    setSearch((prev) => ({ ...prev, currentIndex: newIndex }));

    // Scroll to the message
    const messageIndex = allMessages.findIndex(
      (m) => m.id === search.results[newIndex].messageId
    );
    if (messageIndex >= 0 && listRef.current) {
      listRef.current.scrollToRow({ index: messageIndex, align: 'center' });
    }
  }, [search, allMessages, listRef]);

  // Navigate to previous search result
  const prevResult = useCallback(() => {
    if (search.results.length === 0) return;

    const newIndex =
      search.currentIndex <= 0
        ? search.results.length - 1
        : search.currentIndex - 1;
    setSearch((prev) => ({ ...prev, currentIndex: newIndex }));

    // Scroll to the message
    const messageIndex = allMessages.findIndex(
      (m) => m.id === search.results[newIndex].messageId
    );
    if (messageIndex >= 0 && listRef.current) {
      listRef.current.scrollToRow({ index: messageIndex, align: 'center' });
    }
  }, [search, allMessages, listRef]);

