  const clearSearch = useCallback(() => {
    setSearch({ query: '', results: [], currentIndex: -1 });
    shouldScrollRef.current = true;
  }, []);

  // Handle keyboard shortcuts for search navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!search.query) return;

      if (e.key === 'Enter' && e.shiftKey) {
        e.preventDefault();
        prevResult();
      } else if (
        e.key === 'Enter' &&
        !e.shiftKey &&
        search.results.length > 0
      ) {
        if (
          (e.target as HTMLElement)?.classList?.contains(styles.searchInput)
        ) {
          e.preventDefault();
          nextResult();
        }
      } else if (e.key === 'Escape') {
        clearSearch();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [search, nextResult, prevResult, clearSearch]);

  // Get highlighted message ID for current search result
  const highlightedMessageId = useMemo(() => {
    if (search.currentIndex >= 0 && search.results[search.currentIndex]) {
      return search.results[search.currentIndex].messageId;
    }
    return null;
  }, [search]);

  // Row props for react-window v2
  const rowProps: RowProps = useMemo(
    () => ({
      messages: allMessages,
      showThinking,
      onToggleMessageCollapse,
      onToggleThinkingCollapse,
      onDeleteMessage,
      onRegenerateMessage,
      highlightedMessageId,
    }),
    [
      allMessages,
      showThinking,
      onToggleMessageCollapse,
      onToggleThinkingCollapse,
      onDeleteMessage,
      onRegenerateMessage,
      highlightedMessageId,
    ]
  );

  if (allMessages.length === 0) {
    return (
      <div className={styles.empty}>
        <WelcomeMessage />
      </div>
    );
  }

  return (
    <div className={styles.container}>
      {/* Search Bar */}
      <div className={styles.searchBar}>
        <div className={styles.searchInputWrapper}>
          <SearchIcon />
          <input
            type="text"
            className={styles.searchInput}
            placeholder="Search messages..."
            value={search.query}
            onChange={(e) => performSearch(e.target.value)}
          />
          {search.query && (
            <button className={styles.clearBtn} onClick={clearSearch}>
              <CloseIcon />
            </button>
          )}
        </div>

        {search.results.length > 0 && (
          <div className={styles.searchNav}>
            <span className={styles.searchCount}>
              {search.currentIndex + 1} / {search.results.length}
            </span>
            <button
              className={styles.navBtn}
              onClick={prevResult}
              title="Previous (Shift+Enter)"
            >
              <ChevronUpIcon />
            </button>
            <button
              className={styles.navBtn}
              onClick={nextResult}
              title="Next (Enter)"
            >
              <ChevronDownIcon />
            </button>
          </div>
        )}
      </div>

      {/* Virtual Message List */}
      <div ref={outerRef} className={styles.listContainer}>
        <List<RowProps>
          listRef={listRef}
          height={listHeight}
          rowCount={allMessages.length}
          rowHeight={120}
          rowProps={rowProps}
          rowComponent={MessageRow}
          className={styles.list}
        />
      </div>

      {/* Scroll to bottom button */}
      {!shouldScrollRef.current && (
        <button
          className={styles.scrollToBottom}
          onClick={() => {
            if (listRef.current) {
              listRef.current.scrollToRow({
                index: allMessages.length - 1,
                align: 'end',
              });
              shouldScrollRef.current = true;
            }
          }}
          title="Scroll to bottom"
        >
          <ChevronDownIcon />
        </button>
      )}
    </div>
  );
}

