export function createSidebarController(): SidebarController {
	// Direct store access without hook
	const store = useSidebarStore.getState();

	return {
		loadWorkingDir: async () => {
			store.setLoading(true);
			try {
				const { cwd } = await fetchApi<WorkingDirResponse>("/working-dir");
				store.setWorkingDir(cwd);
			} catch (error) {
				store.setError(error instanceof Error ? error.message : "Failed to load working directory");
			} finally {
				store.setLoading(false);
			}
		},

		loadRecentWorkspaces: async () => {
			try {
				const saved = localStorage.getItem("recentWorkspaces");
				store.setRecentWorkspaces(saved ? JSON.parse(saved) : []);
			} catch {
				store.setRecentWorkspaces([]);
			}
		},

		loadSessions: async (cwd: string) => {
			store.setLoading(true);
			try {
				const data = await fetchApi<SessionsResponse>(`/sessions?cwd=${encodeURIComponent(cwd)}`);
				store.setSessions(
					(data.sessions || []).map((s) => ({
						id: s.path,
						name: s.firstMessage?.slice(0, 35) || s.path.split("/").pop() || "Untitled",
						messageCount: s.messageCount || 0,
						lastModified: new Date(s.modified),
						firstMessage: s.firstMessage,
					})),
				);
			} catch (error) {
				store.setError(error instanceof Error ? error.message : "Failed to load sessions");
			} finally {
				store.setLoading(false);
			}
		},

		changeWorkingDir: async (path: string) => {
			store.setLoading(true);
			try {
				wsClient.send({ type: "change_dir", path });
				return new Promise<void>((resolve, reject) => {
					const timeout = setTimeout(() => reject(new Error("Timeout")), 5000);
					const unsub = wsClient.on("dir_changed", (data) => {
						clearTimeout(timeout);
						store.setWorkingDir(data.cwd);
						store.addRecentWorkspace(data.cwd);
						unsub();
						resolve();
					});
				});
			} catch (error) {
				store.setError(error instanceof Error ? error.message : "Failed");
				throw error;
			} finally {
				store.setLoading(false);
			}
		},

		selectSession: (id: string) => {
			store.selectSession(id);
			wsClient.send({ type: "load_session", sessionPath: id });
		},

		createNewSession: async () => {
			store.setLoading(true);
			try {
				wsClient.send({ type: "new_session" });
				return new Promise<void>((resolve, reject) => {
					const timeout = setTimeout(() => reject(new Error("Timeout")), 5000);
					const unsub = wsClient.on("session_created", (data) => {
						clearTimeout(timeout);
						store.selectSession(data.sessionId);
						unsub();
						resolve();
					});
				});
			} catch (error) {
				store.setError(error instanceof Error ? error.message : "Failed");
				throw error;
			} finally {
				store.setLoading(false);
			}
		},

		setSearchQuery: (query: string) => store.setSearchQuery(query),
		setSearchFilters: (filters: Partial<SearchFilters>) => store.setSearchFilters(filters),
		setTheme: (theme: Theme) => {
			store.setTheme(theme);
			document.body.classList.toggle("light-mode", theme === "light");
		},
		setFontSize: (size: FontSize) => {
			store.setFontSize(size);
			document.body.classList.remove("font-tiny", "font-small", "font-medium", "font-large");
			document.body.classList.add(`font-${size}`);
		},
		clearError: () => store.clearError(),
	};
}

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
import { resolve } from 'path';
import { readFileSync } from 'fs';

// Check if we're in UI development mode (mock data)
const isUIDevMode = process.env.GATEWAY_MODE === 'ui';

// Mock API plugin for UI development mode
const mockApiPlugin = () => ({
  name: 'mock-api',
  configureServer(server: any) {
    // Sessions API
    server.middlewares.use('/api/sessions', (req: any, res: any, next: any) => {
      if (req.method === 'GET') {
        const sessions = JSON.parse(readFileSync('./mock-data/sessions/default.json', 'utf-8'));
        res.setHeader('Content-Type', 'application/json');
        res.end(JSON.stringify([sessions]));
        return;
      }
      next();
    });

    // Models API
    server.middlewares.use('/api/models', (req: any, res: any, next: any) => {
      if (req.method === 'GET') {
        const models = JSON.parse(readFileSync('./mock-data/api-responses/models.json', 'utf-8'));
        res.setHeader('Content-Type', 'application/json');
        res.end(JSON.stringify(models));
        return;
      }
      next();
    });

    // System prompt API
    server.middlewares.use('/api/system-prompt', (req: any, res: any, next: any) => {
      if (req.method === 'GET') {
        const prompt = JSON.parse(readFileSync('./mock-data/api-responses/system-prompt.json', 'utf-8'));
        res.setHeader('Content-Type', 'application/json');
        res.end(JSON.stringify(prompt));
        return;
      }
      next();
    });

    // Files API - mock file browser
    server.middlewares.use('/api/files', (req: any, res: any, next: any) => {
      if (req.method === 'GET') {
        const files = [
          { name: 'src', path: '/src', isDirectory: true, size: 0, modified: new Date().toISOString() },
          { name: 'package.json', path: '/package.json', isDirectory: false, size: 1024, modified: new Date().toISOString() },
          { name: 'README.md', path: '/README.md', isDirectory: false, size: 2048, modified: new Date().toISOString() },
        ];
        res.setHeader('Content-Type', 'application/json');
        res.end(JSON.stringify({ path: '/', files }));
        return;
      }
      next();
    });
  },
});

export default defineConfig({
  plugins: [react(), isUIDevMode && mockApiPlugin()].filter(Boolean),
  root: '.',
  build: {
    outDir: 'dist',
    emptyOutDir: false,
    rollupOptions: {
      input: {
        main: resolve(__dirname, 'public/index.html'),
      },
    },
  },
  publicDir: 'public',
  server: {
    port: 5173,
    // In UI dev mode, use mock APIs instead of proxy
    ...(isUIDevMode ? {} : {
      proxy: {
        '/api': 'http://localhost:3001',
        '/ws': {
          target: 'ws://localhost:3001',
          ws: true,
        },
      },
    }),
  },
  test: {
    environment: 'jsdom',
    globals: true,
    setupFiles: ['./test/setup.ts'],
    include: ['src/**/*.test.{ts,tsx}'],
  },
  resolve: {
    alias: {
      '@': resolve(__dirname, 'src'),
    },
  },
});

