 * BottomMenu - 底部固定菜单
 * Features:
 * - 切换左侧面板显示/隐藏
 * - 切换 Chat/File 视图
 */

import styles from './BottomMenu.module.css';

interface BottomMenuProps {
  isSidebarVisible: boolean;
  currentView: 'chat' | 'files';
  onToggleSidebar: () => void;
  onSwitchView: (view: 'chat' | 'files') => void;
}

export function BottomMenu({
  isSidebarVisible,
  currentView,
  onToggleSidebar,
  onSwitchView,
}: BottomMenuProps) {
  return (
    <nav className={styles.bottomMenu}>
      <button
        className={`${styles.menuButton} ${isSidebarVisible ? styles.active : ''}`}
        onClick={onToggleSidebar}
        title={isSidebarVisible ? 'Hide Sidebar' : 'Show Sidebar'}
      >
        <SidebarIcon />
        <span className={styles.label}>Sidebar</span>
      </button>

      <button
        className={`${styles.menuButton} ${currentView === 'chat' ? styles.active : ''}`}
        onClick={() => onSwitchView('chat')}
        title="Chat View"
      >
        <ChatIcon />
        <span className={styles.label}>Chat</span>
      </button>

      <button
        className={`${styles.menuButton} ${currentView === 'files' ? styles.active : ''}`}
        onClick={() => onSwitchView('files')}
        title="File Browser"
      >
        <FilesIcon />
        <span className={styles.label}>Files</span>
      </button>
    </nav>
  );
}

