/**
 * Global Styles - 完整样式系统
 */

/* CSS Variables */
:root {
  /* Dark mode (default) */
  --bg-primary: #0d1117;
  --bg-secondary: #161b22;
  --bg-tertiary: #21262d;
  --bg-hover: #1c2128;
  --border-color: #30363d;
  --border-light: #21262d;
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #6e7681;
  --accent-primary: #2f81f7;
  --accent-hover: #388bfd;
  --accent-secondary: #238636;
  --accent-danger: #f85149;
  --accent-warning: #d29922;
  --accent-purple: #a371f7;
  --accent-bg: rgba(47, 129, 247, 0.1);
  --accent-fg: #58a6ff;
  --radius-sm: 4px;
  --radius-md: 6px;
  --radius-lg: 8px;
  --transition: all 0.15s ease;
  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', monospace;

  /* Compact sizing - Tiny (default) */
  --font-xs: 9px;
  --font-sm: 10px;
  --font-base: 11px;
  --font-md: 12px;
  --font-lg: 13px;
  --space-xs: 2px;
  --space-sm: 3px;
  --space-md: 4px;
  --space-lg: 6px;
  --space-xl: 10px;
}

/* Light mode */
body.light-mode {
  --bg-primary: #ffffff;
  --bg-secondary: #f6f8fa;
  --bg-tertiary: #eaeef2;
  --bg-hover: #f3f4f6;
  --border-color: #d0d7de;
  --border-light: #e5e7eb;
  --text-primary: #24292f;
  --text-secondary: #57606a;
  --text-muted: #8c959f;
  --accent-primary: #0969da;
  --accent-hover: #0550ae;
  --accent-secondary: #1a7f37;
  --accent-danger: #cf222e;
  --accent-warning: #9a6700;
  --accent-purple: #8250df;
  --accent-bg: rgba(9, 105, 218, 0.1);
}

/* Font sizes */
body.font-tiny {
  --font-xs: 9px;
  --font-sm: 10px;
  --font-base: 11px;
  --font-md: 12px;
  --font-lg: 13px;
}

body.font-small {
  --font-xs: 10px;
  --font-sm: 11px;
  --font-base: 12px;
  --font-md: 13px;
  --font-lg: 14px;
  --space-xs: 2px;
  --space-sm: 4px;
  --space-md: 6px;
  --space-lg: 8px;
  --space-xl: 12px;
}

body.font-medium {
  --font-xs: 11px;
  --font-sm: 12px;
  --font-base: 13px;
  --font-md: 14px;
  --font-lg: 16px;
  --space-xs: 3px;
  --space-sm: 5px;
  --space-md: 8px;
  --space-lg: 10px;
  --space-xl: 14px;
}

body.font-large {
  --font-xs: 12px;
  --font-sm: 13px;
  --font-base: 14px;
  --font-md: 16px;
  --font-lg: 18px;
  --space-xs: 4px;
  --space-sm: 6px;
  --space-md: 10px;
  --space-lg: 14px;
  --space-xl: 20px;
}

/* Reset */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body, #root {
  height: 100%;
  overflow: hidden;
}

body {
  font-family: var(--font-sans);
  font-size: var(--font-base);
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.4;
}

/* App layout */
.app {
  display: flex;
  width: 100%;
  height: 100%;
  overflow: hidden;
}

.main {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

/* File browser section (hidden by default) */
.file-browser-section {
  display: none;
  width: 100%;
  height: 100%;
}

.file-browser-section.active {
  display: block;
}

/* Scrollbar styles */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--text-muted);
}

/* Selection highlight for search */
.search-highlight {
  background: var(--accent-warning);
  color: var(--bg-primary);
  padding: 1px 2px;
  border-radius: 2px;
}

/* Animation */
@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes slideUp {
  from { transform: translateY(10px); opacity: 0; }
  to { transform: translateY(0); opacity: 1; }
}

