content.text:
/**
 * SidebarPanel - Main Sidebar Container
 */

import { useEffect } from 'react';
import {
  WorkingDirectory,
  RecentWorkspaces,
  Sessions,
  Search,
  Settings,
} from '../sections';
import { useSidebarStore } from '../../../store/sidebarStore';
import { useSidebarController } from '../../../api/sidebarApi';
import styles from './SidebarPanel.module.css';

interface SidebarPanelProps {
  onSwitchView?: (view: 'chat' | 'files') => void;
  currentView?: 'chat' | 'files';
}

export function SidebarPanel({ onSwitchView, currentView = 'chat' }: SidebarPanelProps) {
  const workingDir = useSidebarStore((state) => state.workingDir);
  const error = useSidebarStore((state) => state.error);
  const controller = useSidebarController();

  // Initial data loading
  useEffect(() => {
    controller.loadWorkingDir();
    controller.loadRecentWorkspaces();
  }, []);

  // Load sessions when working directory changes
  useEffect(() => {
    if (workingDir?.path) {
      controller.loadSessions(workingDir.path);
    }
  }, [workingDir?.path]);

  return (
    <aside className={styles.sidebar}>
      <SidebarHeader />
      <ViewSwitcher currentView={currentView} onSwitchView={onSwitchView} />
      <div className={styles.content}>
        {error && (
          <div className={styles.error}>
            <span>{error}</span>
            <button onClick={controller.clearError}>×</button>
          </div>
        )}
        <WorkingDirectory />
        <RecentWorkspaces />
        <Sessions />
        <Search />
        <Settings />
      </div>
    </aside>
  );
}

function SidebarHeader() {
  return (
    <div className={styles.header}>
      <div className={styles.logo}>π</div>
      <span className={styles.title}>Pi Gateway</span>
    </div>
  );
}

function ViewSwitcher({ 
  currentView, 
  onSwitchView 
}: { 
  currentView: 'chat' | 'files';
  onSwitchView?: (view: 'chat' | 'files') => void;
}) {
  if (!onSwitchView) return null;

  return (
    <div className={styles.viewSwitcher}>
      <button 
        className={`${styles.viewBtn} ${currentView === 'chat' ? styles.active : ''}`}
        onClick={() => onSwitchView('chat')}
        title="Chat View"
      >
        <ChatIcon />
        <span>Chat</span>
      </button>
      <button 
        className={`${styles.viewBtn} ${currentView === 'files' ? styles.active : ''}`}
        onClick={() => onSwitchView('files')}
        title="File Browser"
      >
        <FolderIcon />
        <span>Files</span>
      </button>
    </div>
  );
