/**
 * App - 主应用组件
 * 整合所有功能模块
 */

import { useEffect, useState, useCallback } from 'react';
import { useSessionStore, useModalStore } from './store';
import { initConnection } from './api/client';
import { SidebarPanel } from './components/layout/SidebarPanel/SidebarPanel';
import { BottomMenu } from './components/layout/BottomMenu';
import { ChatPanel } from './components/chat/ChatPanel/ChatPanel';
import { FileBrowser } from './components/files/FileBrowser';
import { FileViewer } from './components/files/FileViewer';
import { SystemPromptModal } from './components/modals/SystemPromptModal';
import { LlmLogModal } from './components/modals/LlmLogModal';
import { ModelSelectorModal } from './components/modals/ModelSelectorModal';
import { ThinkingLevelModal } from './components/modals/ThinkingLevelModal';
import './styles/global.css';

function App() {
  const { theme, fontSize, setCurrentDir } = useSessionStore();
  const { closeAll } = useModalStore();
  const [currentView, setCurrentView] = useState<'chat' | 'files'>('chat');
  const [isSidebarVisible, setIsSidebarVisible] = useState(true);

  // 初始化主题和字体
  useEffect(() => {
    document.body.classList.toggle('light-mode', theme === 'light');
    document.body.classList.remove('font-tiny', 'font-small', 'font-medium', 'font-large');
    document.body.classList.add(`font-${fontSize}`);
  }, [theme, fontSize]);

  // 初始化WebSocket
  useEffect(() => {
    initConnection();
  }, []);

  // 处理视图切换
  const handleSwitchView = useCallback((view: 'chat' | 'files') => {
    setCurrentView(view);
  }, []);

  // 切换侧边栏显示/隐藏
  const handleToggleSidebar = useCallback(() => {
    setIsSidebarVisible(prev => !prev);
  }, []);

  // 加载工作目录
  useEffect(() => {
    const loadWorkingDir = async () => {
      try {
        const res = await fetch('/api/working-dir');
        const data = await res.json();
        setCurrentDir(data.cwd);
      } catch (err) {
        console.error('Failed to load working directory:', err);
      }
    };

    loadWorkingDir();
  }, [setCurrentDir]);

  // 全局错误处理
  useEffect(() => {
    const handleError = (e: ErrorEvent) => {
      console.error('Global error:', e.error);
    };

    window.addEventListener('error', handleError);
    return () => window.removeEventListener('error', handleError);
  }, []);

  // ESC键关闭模态框
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        closeAll();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [closeAll]);

  return (
    <div className={`app ${isSidebarVisible ? 'sidebar-visible' : 'sidebar-hidden'}`}>
      {isSidebarVisible && (
        <SidebarPanel 
          onSwitchView={handleSwitchView} 
          currentView={currentView}
        />
      )}

      <main className="main">
        {currentView === 'chat' ? (
          <ChatPanel />
        ) : (
          <FileBrowser />
        )}
      </main>

      <FileViewer />

      <BottomMenu
        isSidebarVisible={isSidebarVisible}
        currentView={currentView}
        onToggleSidebar={handleToggleSidebar}
        onSwitchView={handleSwitchView}
      />

      <SystemPromptModal />
      <LlmLogModal />
      <ModelSelectorModal />
      <ThinkingLevelModal />
    </div>
  );
}

export default App;

