arguments.content:
/**
 * BottomMenu Styles - Compact
 */

.bottomMenu {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: 44px;
  background: var(--bg-secondary, #1e1e1e);
  border-top: 1px solid var(--border-color, #333);
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 4px;
  z-index: 1000;
  padding: 0 8px;
}

.menuButton {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 6px 16px;
  background: transparent;
  border: none;
  color: var(--text-secondary, #888);
  cursor: pointer;
  transition: all 0.15s ease;
  border-radius: 6px;
  min-width: 80px;
  height: 32px;
}

.menuButton:hover {
  background: var(--bg-hover, #2a2a2a);
  color: var(--text-primary, #fff);
}

.menuButton.active {
  color: var(--accent-color, #4a9eff);
  background: var(--bg-active, rgba(74, 158, 255, 0.15));
}

.menuButton svg {
  width: 16px;
  height: 16px;
}

.label {
  font-size: 12px;
  font-weight: 500;
}

/* Mobile adjustments */
@media (max-width: 480px) {
  .menuButton {
    padding: 6px 12px;
    min-width: 70px;
  }

  .label {
    font-size: 11px;
  }
}

